// Boolean/string value checking
function isTruthy(T) {
    if (!T) return false;
    if (typeof T === "boolean") return T;
    const R = T.toLowerCase().trim();
    return ["1", "true", "yes", "on"].includes(R);
}

function isFalsy(T) {
    if (T === undefined) return false;
    if (typeof T === "boolean") return !T;
    if (!T) return false;
    const R = T.toLowerCase().trim();
    return ["0", "false", "no", "off"].includes(R);
}

// Check NODE_OPTIONS for flags
function hasNodeOption(T) {
    const R = process.env.NODE_OPTIONS;
    if (!R) return false;
    return R.split(/\s+/).includes(T);
}

// Parse -e KEY=value style env vars (CLI args)
function parseEnvironmentVariables(T) {
    const R = {};
    if (T) for (const A of T) {
        const [_, ...B] = A.split("=");
        if (!_ || B.length === 0) throw new Error(`Invalid env var: ${A}`);
        R[_] = B.join("=");
    }
    return R;
}

// Simple memoization with cache
function memoize(fn, resolver) {
    const memoized = function(...args) {
        const key = resolver ? resolver.apply(this, args) : args[0];
        if (memoized.cache.has(key)) return memoized.cache.get(key);
        const result = fn.apply(this, args);
        memoized.cache.set(key, result);
        return result;
    };
    memoized.cache = new Map();
    return memoized;
}
