/**
 * TodoWrite Tool
 *
 * Session-scoped progress tracking for agents.
 * Based on Claude Code's TodoWrite pattern - tracks work within a conversation.
 * 
 * Key features:
 * - content: Imperative form ("Fix the bug")
 * - activeForm: Present continuous ("Fixing the bug") 
 * - status: pending | in_progress | completed
 */

import { Type } from "@sinclair/typebox";
import { jsonResult, readStringParam, readArrayParam, type AnyAgentTool } from "./common.js";

// ═══════════════════════════════════════════════════════════════════════════
// SCHEMAS
// ═══════════════════════════════════════════════════════════════════════════

const TodoStatusSchema = Type.Union([
  Type.Literal("pending"),
  Type.Literal("in_progress"),
  Type.Literal("completed"),
]);

const TodoItemSchema = Type.Object({
  content: Type.String({
    minLength: 1,
    description: "Task description in imperative form (e.g., 'Fix the login bug')",
  }),
  status: TodoStatusSchema,
  activeForm: Type.String({
    minLength: 1,
    description: "Present continuous form (e.g., 'Fixing the login bug')",
  }),
});

const TodoWriteInputSchema = Type.Object({
  todos: Type.Array(TodoItemSchema, {
    description: "The updated todo list",
  }),
});

const TodoItemOutputSchema = Type.Object({
  content: Type.String(),
  status: Type.String(),
  activeForm: Type.String(),
});

const TodoWriteOutputSchema = Type.Object({
  oldTodos: Type.Array(TodoItemOutputSchema, {
    description: "The todo list before the update",
  }),
  newTodos: Type.Array(TodoItemOutputSchema, {
    description: "The todo list after the update",
  }),
});

// ═══════════════════════════════════════════════════════════════════════════
// SESSION-SCOPED STORAGE
// ═══════════════════════════════════════════════════════════════════════════

// Store todos per session (sessionId -> todos)
const sessionTodos = new Map<string, TodoItem[]>();

interface TodoItem {
  content: string;
  status: "pending" | "in_progress" | "completed";
  activeForm: string;
}

/**
 * Get todos for a session
 */
export function getSessionTodos(sessionId: string): TodoItem[] {
  return sessionTodos.get(sessionId) ?? [];
}

/**
 * Set todos for a session
 */
export function setSessionTodos(sessionId: string, todos: TodoItem[]): void {
  // Clear empty completed lists (all done = reset)
  const filtered = todos.filter((t) => t.status !== "completed");
  if (filtered.length === 0) {
    sessionTodos.delete(sessionId);
  } else {
    sessionTodos.set(sessionId, filtered);
  }
}

/**
 * Clear todos for a session
 */
export function clearSessionTodos(sessionId: string): void {
  sessionTodos.delete(sessionId);
}

// ═══════════════════════════════════════════════════════════════════════════
// TOOL DEFINITION
// ═══════════════════════════════════════════════════════════════════════════

const SYSTEM_PROMPT = `Update the todo list for the current session. To be used proactively and often to track progress and pending tasks. Make sure that at least one task is in_progress at all times. Always provide both content (imperative) and activeForm (present continuous) for each task.

## When to Use This Tool

Use this tool proactively in these scenarios:

1. **Complex multi-step tasks** - When a task requires 3 or more distinct steps or actions
2. **Non-trivial tasks** - Tasks that require careful planning or multiple operations
3. **User explicitly requests todo list** - When the user directly asks you to use the todo list
4. **User provides multiple tasks** - When users provide a list of things to be done
5. **After receiving new instructions** - Immediately capture user requirements as todos
6. **When you start working on a task** - Mark it as in_progress BEFORE beginning work
7. **After completing a task** - Mark it as completed and add any new follow-up tasks

## When NOT to Use This Tool

Skip using this tool when:
1. There is only a single, straightforward task
2. The task is trivial and tracking it provides no organizational benefit
3. The task can be completed in less than 3 trivial steps
4. The task is purely conversational or informational

## Rules

- Always have one task as in_progress (ideally only one)
- Provide both content (imperative) AND activeForm (continuous)
- Mark in_progress BEFORE starting the work
- Clear completed tasks automatically when all are done`;

/**
 * Create the TodoWrite tool for agents
 */
export function createTodoTool(): AnyAgentTool {
  return {
    name: "TodoWrite",
    label: "TodoWrite",
    description:
      "Use this tool to create and manage a structured task list for your current session. This helps you track progress, organize complex tasks, and demonstrate thoroughness to the user.",
    parameters: TodoWriteInputSchema,
    async execute(toolCallId: string, params: Record<string, unknown>, context?: { sessionId?: string }) {
      const sessionId = context?.sessionId ?? "default";
      const todos = readArrayParam(params, "todos") as Array<{
        content: string;
        status: string;
        activeForm: string;
      }> ?? [];

      // Get old todos
      const oldTodos = getSessionTodos(sessionId);

      // Validate and normalize todos
      const normalizedTodos: TodoItem[] = todos.map((t) => ({
        content: t.content,
        status: t.status as "pending" | "in_progress" | "completed",
        activeForm: t.activeForm,
      }));

      // Store new todos (filter completed if all done)
      setSessionTodos(sessionId, normalizedTodos);

      return jsonResult({
        oldTodos: oldTodos.map((t) => ({
          content: t.content,
          status: t.status,
          activeForm: t.activeForm,
        })),
        newTodos: normalizedTodos.map((t) => ({
          content: t.content,
          status: t.status,
          activeForm: t.activeForm,
        })),
      });
    },
  };
}

/**
 * Get todos as a formatted string (for system prompts)
 */
export function getTodosAsPrompt(sessionId: string): string | null {
  const todos = getSessionTodos(sessionId);
  if (todos.length === 0) return null;

  const lines = todos.map((t) => {
    const check = t.status === "completed" ? "☑" : t.status === "in_progress" ? "▶" : "○";
    return `${check} ${t.content}`;
  });

  return `Current todos:\n${lines.join("\n")}`;
}

/**
 * Get reminder if todos haven't been used
 */
export function getTodoReminder(sessionId: string): string | null {
  const todos = getSessionTodos(sessionId);

  if (todos.length === 0) {
    return null;
  }

  const inProgress = todos.filter((t) => t.status === "in_progress");
  if (inProgress.length === 0) {
    return `You have ${todos.length} todos but none are in_progress. Mark one as in_progress before starting work.`;
  }

  return null;
}

