import type { LspServerConfig } from "./config-types.js";

const log = createSubsystemLogger("lsp");

// ============================================================================
// LSP MESSAGE CONNECTION (SIMPLIFIED JSON-RPC)
// ============================================================================

interface JsonRpcMessage {
  jsonrpc: "2.0";
  id?: number | string;
  method?: string;
  params?: unknown;
  result?: unknown;
  error?: { code: number; message: string; data?: unknown };
}

/**
 * Simplified JSON-RPC message connection over stdio
 */
class MessageConnection {
  private messageId = 0;
  private pendingRequests = new Map<number | string, {
    resolve: (value: unknown) => void;
    reject: (error: Error) => void;
  }>();
  private notificationHandlers = new Map<string, (params: unknown) => void>();
  private buffer = "";
  private isClosed = false;

  constructor(
    private stdout: NodeJS.ReadableStream,
    private stdin: NodeJS.WritableStream
  ) {
    this.startReading();
  }

  private startReading(): void {
    this.stdout.on("data", (data: Buffer) => {
      this.buffer += data.toString();
      this.processBuffer();
    });
  }

  private processBuffer(): void {
    while (true) {
      // Look for Content-Length header
      const headerEnd = this.buffer.indexOf("\r\n\r\n");
      if (headerEnd === -1) break;

      const header = this.buffer.slice(0, headerEnd);
      const contentLengthMatch = header.match(/Content-Length: (\d+)/i);
      if (!contentLengthMatch) {
        this.buffer = this.buffer.slice(headerEnd + 4);
        continue;
      }

      const contentLength = parseInt(contentLengthMatch[1], 10);
      const messageStart = headerEnd + 4;
      const messageEnd = messageStart + contentLength;

      if (this.buffer.length < messageEnd) break;

      const messageStr = this.buffer.slice(messageStart, messageEnd);
      this.buffer = this.buffer.slice(messageEnd);

      try {
        const message = JSON.parse(messageStr) as JsonRpcMessage;
        this.handleMessage(message);
      } catch (err) {
        log.error(`Failed to parse LSP message: ${err}`);
      }
    }
  }

  private handleMessage(message: JsonRpcMessage): void {
    if (message.id !== undefined) {
      // Response to a request
      const pending = this.pendingRequests.get(message.id);
      if (pending) {
        this.pendingRequests.delete(message.id);
        if (message.error) {
          pending.reject(new Error(message.error.message));
        } else {
          pending.resolve(message.result);
        }
      }
    } else if (message.method) {
      // Notification
      const handler = this.notificationHandlers.get(message.method);
      if (handler) {
        handler(message.params);
      }
    }
  }

  async sendRequest<T = unknown>(method: string, params?: unknown): Promise<T> {
    if (this.isClosed) {
      throw new Error("Connection is closed");
    }

    const id = ++this.messageId;
    const message: JsonRpcMessage = {
      jsonrpc: "2.0",
      id,
      method,
      params,
    };

    return new Promise<T>((resolve, reject) => {
      this.pendingRequests.set(id, {
        resolve: (value) => resolve(value as T),
        reject,
      });

      const content = JSON.stringify(message);
      const header = `Content-Length: ${Buffer.byteLength(content)}\r\n\r\n`;

      this.stdin.write(header + content, (err) => {
        if (err) {
          this.pendingRequests.delete(id);
          reject(err);
        }
      });
    });
  }

  sendNotification(method: string, params?: unknown): void {
    if (this.isClosed) return;

    const message: JsonRpcMessage = {
      jsonrpc: "2.0",
      method,
      params,
    };

    const content = JSON.stringify(message);
    const header = `Content-Length: ${Buffer.byteLength(content)}\r\n\r\n`;
    this.stdin.write(header + content);
  }

  onNotification(method: string, handler: (params: unknown) => void): void {
    this.notificationHandlers.set(method, handler);
  }

  onClose(callback: () => void): void {
    this.stdout.on("close", callback);
  }

  close(): void {
    this.isClosed = true;
  }
}

// ============================================================================
// LSP SERVER INSTANCE
// ============================================================================

export type LspServerState = "stopped" | "starting" | "running" | "crashed";

export interface LspServerInstance {
  name: string;
  config: LspServerConfig;
  state: LspServerState;
  process?: ChildProcess;
  connection?: MessageConnection;
  capabilities?: InitializeResult["capabilities"];
  rootUri?: string;
  restartCount: number;
}

// ============================================================================
// LSP SERVER MANAGER
// ============================================================================

export class LspServerManager {
  private servers = new Map<string, LspServerInstance>();
  private openFiles = new Map<string, string>(); // uri -> serverName
  private diagnosticHandler?: (params: PublishDiagnosticsParams) => void;

  constructor(
    private workspaceRoot: string,
    private clientInfo: { name: string; version?: string } = { name: "OpenClaw", version: "1.0.0" }
  ) {}

  /**
   * Register an LSP server configuration
   */
  registerServer(name: string, config: LspServerConfig): void {
    if (this.servers.has(name)) {
      log.warn(`LSP server "${name}" already registered, replacing`);
    }

    this.servers.set(name, {
      name,
      config,
      state: "stopped",
      restartCount: 0,
    });

    log.info(`Registered LSP server: ${name}`);
  }

  /**
   * Get all registered servers
   */
  getServers(): Map<string, LspServerInstance> {
    return this.servers;
  }

  /**
   * Get server for a file
   */
  getServerForFile(filePath: string): LspServerInstance | undefined {
    const ext = path.extname(filePath).toLowerCase();

    for (const server of this.servers.values()) {
      if (ext in server.config.extensionToLanguage) {
        return server;
      }
    }

    return undefined;
  }

  /**
   * Start an LSP server
   */
  async startServer(name: string): Promise<void> {
    const server = this.servers.get(name);
    if (!server) {
      throw new Error(`LSP server "${name}" not registered`);
    }

    if (server.state === "running") {
      log.debug(`LSP server "${name}" already running`);
      return;
    }

    server.state = "starting";
    log.info(`Starting LSP server: ${name}`);

    try {
      // Spawn the LSP server process
      server.process = spawn(server.config.command, server.config.args || [], {
        stdio: ["pipe", "pipe", "pipe"],
        env: server.config.env 
          ? { ...process.env, ...server.config.env }
          : process.env,
        cwd: server.config.workspaceFolder || this.workspaceRoot,
        windowsHide: true,
      });

      if (!server.process.stdout || !server.process.stdin) {
        throw new Error("LSP server process stdio not available");
      }

      // Handle stderr
      server.process.stderr?.on("data", (data: Buffer) => {
        const msg = data.toString().trim();
        if (msg) {
          log.debug(`[LSP ${name}] ${msg}`);
        }
      });

      // Handle process exit
      server.process.on("exit", (code, signal) => {
        if (code !== 0 && code !== null && server.state === "running") {
          log.error(`LSP server "${name}" crashed with exit code ${code}`);
          server.state = "crashed";

          // Auto-restart
          if (server.config.restartOnCrash && server.restartCount < (server.config.maxRestarts || 3)) {
            server.restartCount++;
            log.info(`Restarting LSP server "${name}" (attempt ${server.restartCount})`);
            setTimeout(() => this.startServer(name), 1000);
          }
        }
      });

      server.process.on("error", (err) => {
        log.error(`LSP server "${name}" error: ${err.message}`);
        server.state = "crashed";
      });

      // Create message connection
      server.connection = new MessageConnection(
        server.process.stdout,
        server.process.stdin
      );

      // Handle diagnostics
      server.connection.onNotification("textDocument/publishDiagnostics", (params) => {
        if (this.diagnosticHandler) {
          this.diagnosticHandler(params as PublishDiagnosticsParams);
        }
      });

      server.connection.onClose(() => {
        log.info(`LSP server "${name}" connection closed`);
        server.state = "stopped";
      });

      // Initialize the server
      const initParams: InitializeParams = {
        processId: process.pid,
        clientInfo: this.clientInfo,
        rootUri: pathToFileURL(this.workspaceRoot).href,
        capabilities: {
          textDocument: {
            completion: { dynamicRegistration: false },
            hover: { dynamicRegistration: false, contentFormat: ["markdown", "plaintext"] },
            definition: { dynamicRegistration: false },
            references: { dynamicRegistration: false },
            documentSymbol: { dynamicRegistration: false },
            publishDiagnostics: {
              relatedInformation: true,
              tagSupport: { valueSet: [1, 2] },
              versionSupport: true,
            },
          },
          workspace: {
            workspaceFolders: true,
            configuration: false,
            symbol: { dynamicRegistration: false },
          },
        },
        workspaceFolders: [
          {
            uri: pathToFileURL(this.workspaceRoot).href,
            name: path.basename(this.workspaceRoot),
          },
        ],
      };

      if (server.config.initializationOptions) {
        initParams.initializationOptions = server.config.initializationOptions;
      }

      // Send initialize request with timeout
      const timeout = server.config.startupTimeout || 10000;
      const result = await Promise.race([
        server.connection.sendRequest<InitializeResult>("initialize", initParams),
        new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error(`LSP server startup timeout (${timeout}ms)`)), timeout)
        ),
      ]);

      server.capabilities = result.capabilities;
      server.rootUri = initParams.rootUri;
      server.state = "running";
      server.restartCount = 0;

      // Send initialized notification
      server.connection.sendNotification("initialized", {});

      log.info(`LSP server "${name}" initialized successfully`);
      log.debug(`LSP server "${name}" capabilities: ${JSON.stringify(result.capabilities)}`);

    } catch (err) {
      server.state = "crashed";
      const error = err as Error;
      log.error(`Failed to start LSP server "${name}": ${error.message}`);
      throw error;
    }
  }

  /**
   * Stop an LSP server
   */
  async stopServer(name: string): Promise<void> {
    const server = this.servers.get(name);
    if (!server) return;

    if (server.state !== "running" || !server.connection || !server.process) {
      server.state = "stopped";
      return;
    }

    log.info(`Stopping LSP server: ${name}`);

    try {
      // Send shutdown request
      await server.connection.sendRequest("shutdown", undefined);

      // Send exit notification
      server.connection.sendNotification("exit", undefined);

      // Close connection
      server.connection.close();

      // Wait for process to exit
      const timeout = server.config.shutdownTimeout || 5000;
      await Promise.race([
        new Promise<void>((resolve) => {
          server.process!.on("exit", () => resolve());
        }),
        new Promise<void>((resolve) => setTimeout(resolve, timeout)),
      ]);

      // Force kill if still running
      if (server.process.kill(0)) {
        server.process.kill("SIGTERM");
      }

    } catch (err) {
      log.warn(`Error stopping LSP server "${name}": ${(err as Error).message}`);
    } finally {
      server.state = "stopped";
      server.connection = undefined;
      server.process = undefined;
    }
  }

  /**
   * Stop all servers
   */
  async stopAll(): Promise<void> {
    const stops = Array.from(this.servers.keys()).map((name) => this.stopServer(name));
    await Promise.all(stops);
  }

  /**
   * Set diagnostic handler
   */
  onDiagnostics(handler: (params: PublishDiagnosticsParams) => void): void {
    this.diagnosticHandler = handler;
  }

  // ==========================================================================
  // FILE SYNCHRONIZATION
  // ==========================================================================

  /**
   * Notify server that a file was opened
   */
  async didOpen(filePath: string, content: string): Promise<void> {
    const server = this.getServerForFile(filePath);
    if (!server || server.state !== "running" || !server.connection) {
      return;
    }

    const uri = pathToFileURL(path.resolve(filePath)).href;

    // Check if already open
    if (this.openFiles.get(uri) === server.name) {
      log.debug(`File already open, skipping didOpen for ${filePath}`);
      return;
    }

    const languageId = server.config.extensionToLanguage[path.extname(filePath).toLowerCase()] || "plaintext";

    try {
      server.connection.sendNotification("textDocument/didOpen", {
        textDocument: {
          uri,
          languageId,
          version: 1,
          text: content,
        },
      });

      this.openFiles.set(uri, server.name);
      log.debug(`Sent didOpen for ${filePath} (languageId: ${languageId})`);
    } catch (err) {
      log.error(`Failed to send didOpen for ${filePath}: ${(err as Error).message}`);
    }
  }

  /**
   * Notify server that a file changed
   */
  async didChange(filePath: string, content: string): Promise<void> {
    const server = this.getServerForFile(filePath);
    if (!server || server.state !== "running" || !server.connection) {
      return this.didOpen(filePath, content);
    }

    const uri = pathToFileURL(path.resolve(filePath)).href;

    // If file isn't open, open it first
    if (this.openFiles.get(uri) !== server.name) {
      return this.didOpen(filePath, content);
    }

    try {
      server.connection.sendNotification("textDocument/didChange", {
        textDocument: {
          uri,
          version: Date.now(),
        },
        contentChanges: [{ text: content }],
      });

      log.debug(`Sent didChange for ${filePath}`);
    } catch (err) {
      log.error(`Failed to send didChange for ${filePath}: ${(err as Error).message}`);
    }
  }

  /**
   * Notify server that a file was saved
   */
  async didSave(filePath: string): Promise<void> {
    const server = this.getServerForFile(filePath);
    if (!server || server.state !== "running" || !server.connection) {
      return;
    }

    const uri = pathToFileURL(path.resolve(filePath)).href;

    try {
      server.connection.sendNotification("textDocument/didSave", {
        textDocument: { uri },
      });

      log.debug(`Sent didSave for ${filePath}`);
    } catch (err) {
      log.error(`Failed to send didSave for ${filePath}: ${(err as Error).message}`);
    }
  }

  /**
   * Notify server that a file was closed
   */
  async didClose(filePath: string): Promise<void> {
    const server = this.getServerForFile(filePath);
    if (!server || server.state !== "running" || !server.connection) {
      return;
    }

    const uri = pathToFileURL(path.resolve(filePath)).href;

    try {
      server.connection.sendNotification("textDocument/didClose", {
        textDocument: { uri },
      });

      this.openFiles.delete(uri);
      log.debug(`Sent didClose for ${filePath}`);
    } catch (err) {
      log.error(`Failed to send didClose for ${filePath}: ${(err as Error).message}`);
    }
  }

  // ==========================================================================
  // LSP REQUESTS
  // ==========================================================================

  /**
   * Go to definition
   */
  async goToDefinition(filePath: string, position: Position): Promise<Definition | null> {
    return this.sendRequest(filePath, "textDocument/definition", {
      textDocument: { uri: pathToFileURL(path.resolve(filePath)).href },
      position: { line: position.line - 1, character: position.character - 1 },
    });
  }

  /**
   * Find references
   */
  async findReferences(
    filePath: string,
    position: Position,
    includeDeclaration = true
  ): Promise<Location[] | null> {
    return this.sendRequest(filePath, "textDocument/references", {
      textDocument: { uri: pathToFileURL(path.resolve(filePath)).href },
      position: { line: position.line - 1, character: position.character - 1 },
      context: { includeDeclaration },
    });
  }

  /**
   * Get hover info
   */
  async hover(filePath: string, position: Position): Promise<Hover | null> {
    return this.sendRequest(filePath, "textDocument/hover", {
      textDocument: { uri: pathToFileURL(path.resolve(filePath)).href },
      position: { line: position.line - 1, character: position.character - 1 },
    });
  }

  /**
   * Get document symbols
   */
  async documentSymbol(filePath: string): Promise<DocumentSymbol[] | SymbolInformation[] | null> {
    return this.sendRequest(filePath, "textDocument/documentSymbol", {
      textDocument: { uri: pathToFileURL(path.resolve(filePath)).href },
    });
  }

  /**
   * Go to implementation
   */
  async goToImplementation(filePath: string, position: Position): Promise<Implementation | null> {
    return this.sendRequest(filePath, "textDocument/implementation", {
      textDocument: { uri: pathToFileURL(path.resolve(filePath)).href },
      position: { line: position.line - 1, character: position.character - 1 },
    });
  }

  /**
   * Get completions
   */
  async completion(filePath: string, position: Position): Promise<CompletionList | null> {
    return this.sendRequest(filePath, "textDocument/completion", {
      textDocument: { uri: pathToFileURL(path.resolve(filePath)).href },
      position: { line: position.line - 1, character: position.character - 1 },
    });
  }

  /**
   * Prepare call hierarchy
   */
  async prepareCallHierarchy(
    filePath: string,
    position: Position
  ): Promise<CallHierarchyItem[] | null> {
    return this.sendRequest(filePath, "textDocument/prepareCallHierarchy", {
      textDocument: { uri: pathToFileURL(path.resolve(filePath)).href },
      position: { line: position.line - 1, character: position.character - 1 },
    });
  }

  /**
   * Get incoming calls
   */
  async incomingCalls(item: CallHierarchyItem): Promise<CallHierarchyIncomingCall[] | null> {
    const server = this.getServerForFile(this.uriToPath(item.uri));
    if (!server || server.state !== "running" || !server.connection) {
      return null;
    }
    return server.connection.sendRequest("callHierarchy/incomingCalls", { item });
  }

  /**
   * Get outgoing calls
   */
  async outgoingCalls(item: CallHierarchyItem): Promise<CallHierarchyOutgoingCall[] | null> {
    const server = this.getServerForFile(this.uriToPath(item.uri));
    if (!server || server.state !== "running" || !server.connection) {
      return null;
    }
    return server.connection.sendRequest("callHierarchy/outgoingCalls", { item });
  }

  /**
   * Generic request helper
   */
  private async sendRequest<T>(
    filePath: string,
    method: string,
    params: unknown
  ): Promise<T | null> {
    const server = this.getServerForFile(filePath);
    if (!server) {
      log.debug(`No LSP server for file ${filePath}`);
      return null;
    }

    if (server.state !== "running" || !server.connection) {
      // Try to start the server
      try {
        await this.startServer(server.name);
      } catch (err) {
        log.error(`Failed to start LSP server for ${filePath}: ${(err as Error).message}`);
        return null;
      }
    }

    if (!server.connection) {
      return null;
    }

    try {
      return await server.connection.sendRequest<T>(method, params);
    } catch (err) {
      log.error(`LSP request failed for ${filePath}, method '${method}': ${(err as Error).message}`);
      throw err;
    }
  }

  /**
   * Convert file URI to path
   */
  private uriToPath(uri: string): string {
    let path = uri.replace(/^file:\/\//, "");
    if (/^\/[A-Za-z]:/.test(path)) {
      path = path.slice(1);
    }
    try {
      path = decodeURIComponent(path);
    } catch {
      // ignore
    }
    return path;
  }
}

// ============================================================================
// SINGLETON INSTANCE
// ============================================================================

let defaultManager: LspServerManager | null = null;

/**
 * Get or create the default LSP server manager
 */
export function getLspServerManager(workspaceRoot?: string): LspServerManager {
  if (!defaultManager && workspaceRoot) {
    defaultManager = new LspServerManager(workspaceRoot);
  }
  if (!defaultManager) {
    throw new Error("LSP server manager not initialized. Call getLspServerManager(workspaceRoot) first.");
  }
  return defaultManager;
}

/**
 * Reset the default manager (for testing)
 */
export function resetLspServerManager(): void {
  defaultManager = null;
}

/**
 * LSP Tool
 * 
 * Agent tool for LSP operations: definition, references, hover, symbols, etc.
 */

import { z } from "zod";
import path from "node:path";
import { pathToFileURL } from "node:url";
import { createTool, type Tool, type ToolResult } from "./common.js";
import { getLspServerManager, resetLspServerManager } from "../../lsp/server-manager.js";
import {
  LSP_SERVER_PRESETS,
  lspServerConfigSchema,
  type LspServerConfig,
} from "../../lsp/config-types.js";
import type { Position, Location, DocumentSymbol, SymbolInformation } from "../../lsp/types.js";

// ============================================================================
// LSP TOOL SCHEMA
// ============================================================================

const positionSchema = z.object({
  line: z.number().int().positive().describe("Line number (1-indexed)"),
  character: z.number().int().positive().describe("Character offset (1-indexed)"),
});

const lspOperationSchema = z.enum([
  "goToDefinition",
  "findReferences",
  "hover",
  "documentSymbol",
  "workspaceSymbol",
  "goToImplementation",
  "prepareCallHierarchy",
  "incomingCalls",
  "outgoingCalls",
  "completion",
  "registerServer",
  "listServers",
  "startServer",
  "stopServer",
]);

export const lspToolSchema = {
  operation: lspOperationSchema.describe("LSP operation to perform"),
  filePath: z.string().optional().describe("File path (absolute or relative to workspace)"),
  position: positionSchema.optional().describe("Position in the file (for position-based operations)"),
  query: z.string().optional().describe("Query string (for workspaceSymbol)"),
  serverName: z.string().optional().describe("LSP server name (for registerServer, startServer, stopServer)"),
  serverConfig: z.record(z.unknown()).optional().describe("LSP server configuration (for registerServer)"),
  callHierarchyItem: z.unknown().optional().describe("Call hierarchy item (for incomingCalls/outgoingCalls)"),
};

// ============================================================================
// LSP TOOL IMPLEMENTATION
// ============================================================================

export function createLspTool(workspaceRoot: string): Tool<typeof lspToolSchema> {
  return createTool({
    name: "LSP",
    description: `Language Server Protocol (LSP) tool for code intelligence.

Operations:
- goToDefinition: Navigate to the definition of a symbol
- findReferences: Find all references to a symbol
- hover: Get type information and documentation at a position
- documentSymbol: List all symbols in a document
- workspaceSymbol: Search symbols across the workspace
- goToImplementation: Navigate to implementations of an interface
- prepareCallHierarchy: Get call hierarchy for a function/method
- incomingCalls: Get callers of a function (use after prepareCallHierarchy)
- outgoingCalls: Get callees of a function (use after prepareCallHierarchy)
- completion: Get code completions at a position
- registerServer: Register a new LSP server configuration
- listServers: List all registered LSP servers
- startServer: Manually start an LSP server
- stopServer: Stop an LSP server

Common LSP servers:
- TypeScript: typescript-language-server --stdio
- Python: pylsp
- Rust: rust-analyzer
- Go: gopls
- C/C++: clangd

File positions are 1-indexed (line 1, character 1 = start of file).`,
    parameters: lspToolSchema,
    execute: async (params): Promise<ToolResult> => {
      const { operation, filePath, position, query, serverName, serverConfig, callHierarchyItem } = params;

      try {
        const manager = getLspServerManager(workspaceRoot);

        switch (operation) {
          case "registerServer": {
            if (!serverName || !serverConfig) {
              return {
                success: false,
                error: "serverName and serverConfig are required for registerServer",
              };
            }

            try {
              const config = lspServerConfigSchema.parse(serverConfig);
              manager.registerServer(serverName, config);
              return {
                success: true,
                output: `Registered LSP server: ${serverName}`,
              };
            } catch (err) {
              return {
                success: false,
                error: `Invalid server config: ${(err as Error).message}`,
              };
            }
          }

          case "listServers": {
            const servers = Array.from(manager.getServers().entries()).map(([name, instance]) => ({
              name,
              state: instance.state,
              extensions: Object.keys(instance.config.extensionToLanguage),
            }));

            return {
              success: true,
              output: servers.length > 0
                ? `Registered LSP servers:\n${servers.map((s) => 
                    `- ${s.name}: ${s.state} (${s.extensions.join(", ")})`
                  ).join("\n")}`
                : "No LSP servers registered",
              data: servers,
            };
          }

          case "startServer": {
            if (!serverName) {
              return {
                success: false,
                error: "serverName is required for startServer",
              };
            }

            await manager.startServer(serverName);
            return {
              success: true,
              output: `Started LSP server: ${serverName}`,
            };
          }

          case "stopServer": {
            if (!serverName) {
              return {
                success: false,
                error: "serverName is required for stopServer",
              };
            }

            await manager.stopServer(serverName);
            return {
              success: true,
              output: `Stopped LSP server: ${serverName}`,
            };
          }

          case "goToDefinition": {
            if (!filePath || !position) {
              return {
                success: false,
                error: "filePath and position are required for goToDefinition",
              };
            }

            const resolvedPath = resolveFilePath(filePath, workspaceRoot);
            const result = await manager.goToDefinition(resolvedPath, position);

            if (!result) {
              return {
                success: true,
                output: "No definition found",
              };
            }

            const locations = Array.isArray(result) ? result : [result];
            return {
              success: true,
              output: formatLocations(locations, "Definition"),
              data: locations,
            };
          }

          case "findReferences": {
            if (!filePath || !position) {
              return {
                success: false,
                error: "filePath and position are required for findReferences",
              };
            }

            const resolvedPath = resolveFilePath(filePath, workspaceRoot);
            const result = await manager.findReferences(resolvedPath, position);

            if (!result || result.length === 0) {
              return {
                success: true,
                output: "No references found",
              };
            }

            return {
              success: true,
              output: formatLocations(result, "References"),
              data: result,
            };
          }

          case "hover": {
            if (!filePath || !position) {
              return {
                success: false,
                error: "filePath and position are required for hover",
              };
            }

            const resolvedPath = resolveFilePath(filePath, workspaceRoot);
            const result = await manager.hover(resolvedPath, position);

            if (!result) {
              return {
                success: true,
                output: "No hover information available",
              };
            }

            const content = formatHoverContent(result.contents);
            return {
              success: true,
              output: content,
              data: result,
            };
          }

          case "documentSymbol": {
            if (!filePath) {
              return {
                success: false,
                error: "filePath is required for documentSymbol",
              };
            }

            const resolvedPath = resolveFilePath(filePath, workspaceRoot);
            const result = await manager.documentSymbol(resolvedPath);

            if (!result || result.length === 0) {
              return {
                success: true,
                output: "No symbols found in document",
              };
            }

            const formatted = formatSymbols(result);
            return {
              success: true,
              output: `Document symbols:\n${formatted}`,
              data: result,
            };
          }

          case "workspaceSymbol": {
            const result = await manager.getServers().values().next().value?.connection?.sendRequest<
              SymbolInformation[]
            >("workspace/symbol", { query: query || "" });

            if (!result || result.length === 0) {
              return {
                success: true,
                output: "No symbols found",
              };
            }

            return {
              success: true,
              output: `Workspace symbols:\n${result.map((s) => 
                `- ${s.name} (${symbolKindToString(s.kind)}) - ${uriToPath(s.location.uri)}`
              ).join("\n")}`,
              data: result,
            };
          }

          case "goToImplementation": {
            if (!filePath || !position) {
              return {
                success: false,
                error: "filePath and position are required for goToImplementation",
              };
            }

            const resolvedPath = resolveFilePath(filePath, workspaceRoot);
            const result = await manager.goToImplementation(resolvedPath, position);

            if (!result) {
              return {
                success: true,
                output: "No implementations found",
              };
            }

            const locations = Array.isArray(result) ? result : [result];
            return {
              success: true,
              output: formatLocations(locations, "Implementations"),
              data: locations,
            };
          }

          case "prepareCallHierarchy": {
            if (!filePath || !position) {
              return {
                success: false,
                error: "filePath and position are required for prepareCallHierarchy",
              };
            }

            const resolvedPath = resolveFilePath(filePath, workspaceRoot);
            const result = await manager.prepareCallHierarchy(resolvedPath, position);

            if (!result || result.length === 0) {
              return {
                success: true,
                output: "No call hierarchy available at this position",
              };
            }

            return {
              success: true,
              output: `Call hierarchy items:\n${result.map((item, i) =>
                `${i + 1}. ${item.name} (${symbolKindToString(item.kind)})\n   ${uriToPath(item.uri)}:${item.selectionRange.start.line + 1}`
              ).join("\n")}`,
              data: result,
            };
          }

          case "incomingCalls": {
            if (!callHierarchyItem) {
              return {
                success: false,
                error: "callHierarchyItem is required for incomingCalls",
              };
            }

            const result = await manager.incomingCalls(callHierarchyItem as any);

            if (!result || result.length === 0) {
              return {
                success: true,
                output: "No incoming calls",
              };
            }

            return {
              success: true,
              output: `Callers:\n${result.map((call, i) =>
                `${i + 1}. ${call.from.name}\n   ${uriToPath(call.from.uri)}:${call.from.selectionRange.start.line + 1}`
              ).join("\n")}`,
              data: result,
            };
          }

          case "outgoingCalls": {
            if (!callHierarchyItem) {
              return {
                success: false,
                error: "callHierarchyItem is required for outgoingCalls",
              };
            }

            const result = await manager.outgoingCalls(callHierarchyItem as any);

            if (!result || result.length === 0) {
              return {
                success: true,
                output: "No outgoing calls",
              };
            }

            return {
              success: true,
              output: `Callees:\n${result.map((call, i) =>
                `${i + 1}. ${call.to.name}\n   ${uriToPath(call.to.uri)}:${call.to.selectionRange.start.line + 1}`
              ).join("\n")}`,
              data: result,
            };
          }

          case "completion": {
            if (!filePath || !position) {
              return {
                success: false,
                error: "filePath and position are required for completion",
              };
            }

            const resolvedPath = resolveFilePath(filePath, workspaceRoot);
            const result = await manager.completion(resolvedPath, position);

            if (!result || result.items.length === 0) {
              return {
                success: true,
                output: "No completions available",
              };
            }

            const items = result.items.slice(0, 20); // Limit to 20 items
            return {
              success: true,
              output: `Completions:\n${items.map((item, i) =>
                `${i + 1}. ${item.label}${item.detail ? ` - ${item.detail}` : ""}`
              ).join("\n")}${result.items.length > 20 ? `\n... and ${result.items.length - 20} more` : ""}`,
              data: result,
            };
          }

          default:
            return {
              success: false,
              error: `Unknown operation: ${operation}`,
            };
        }
      } catch (err) {
        const error = err as Error;
        return {
          success: false,
          error: `LSP error: ${error.message}`,
        };
      }
    },
  });
}

// ============================================================================
// HELPER FUNCTIONS
// ============================================================================

function resolveFilePath(filePath: string, workspaceRoot: string): string {
  if (path.isAbsolute(filePath)) {
    return filePath;
  }
  return path.resolve(workspaceRoot, filePath);
}

function uriToPath(uri: string): string {
  let p = uri.replace(/^file:\/\//, "");
  if (/^\/[A-Za-z]:/.test(p)) {
    p = p.slice(1);
  }
  try {
    p = decodeURIComponent(p);
  } catch {
    // ignore
  }
  return p;
}

function formatLocations(locations: Location[], title: string): string {
  return `${title}:\n${locations.map((loc, i) => {
    const p = uriToPath(loc.uri);
    return `${i + 1}. ${p}:${loc.range.start.line + 1}:${loc.range.start.character + 1}`;
  }).join("\n")}`;
}

function formatHoverContent(contents: unknown): string {
  if (typeof contents === "string") {
    return contents;
  }

  if (typeof contents === "object" && contents !== null) {
    const obj = contents as any;
    if (obj.kind === "markdown" || obj.kind === "plaintext") {
      return obj.value;
    }
    if (obj.language && obj.value) {
      return `\`\`\`${obj.language}\n${obj.value}\n\`\`\``;
    }
    if (Array.isArray(contents)) {
      return (contents as any[]).map(formatHoverContent).join("\n\n");
    }
  }

  return String(contents);
}

function formatSymbols(symbols: DocumentSymbol[] | SymbolInformation[]): string {
  if (symbols.length === 0) return "";

  // Check if DocumentSymbol (has children)
  if ("children" in symbols[0]) {
    return formatDocumentSymbols(symbols as DocumentSymbol[], 0);
  }

  // SymbolInformation
  return (symbols as SymbolInformation[])
    .map((s) => `- ${s.name} (${symbolKindToString(s.kind)})`)
    .join("\n");
}

function formatDocumentSymbols(symbols: DocumentSymbol[], indent: number): string {
  const prefix = "  ".repeat(indent);
  return symbols
    .map((s) => {
      const line = `${prefix}- ${s.name} (${symbolKindToString(s.kind)})${s.detail ? ` - ${s.detail}` : ""}`;
      const children = s.children && s.children.length > 0
        ? "\n" + formatDocumentSymbols(s.children, indent + 1)
        : "";
      return line + children;
    })
    .join("\n");
}

function symbolKindToString(kind: number): string {
  const kinds: Record<number, string> = {
    1: "File",
    2: "Module",
    3: "Namespace",
    4: "Package",
    5: "Class",
    6: "Method",
    7: "Property",
    8: "Field",
    9: "Constructor",
    10: "Enum",
    11: "Interface",
    12: "Function",
    13: "Variable",
    14: "Constant",
    15: "String",
    16: "Number",
    17: "Boolean",
    18: "Array",
    19: "Object",
    20: "Key",
    21: "Null",
    22: "EnumMember",
    23: "Struct",
    24: "Event",
    25: "Operator",
    26: "TypeParameter",
  };
  return kinds[kind] || "Unknown";
}

